// Extract data from merged inputs
const clauseData = $input.first().json.clauses || [];
const riskData = $input.item(1).json.risks || [];
const obligationData = $input.item(2).json.obligations || [];
const summaryData = $input.item(3).json;

// Risk weights by category
const riskWeights = {
  payment_terms: 0.25,
  liability: 0.30,
  termination: 0.15,
  ip: 0.15,
  confidentiality: 0.10,
  warranty: 0.03,
  indemnification: 0.02
};

// Risk level scores
const riskScores = {
  critical: 1.0,
  high: 0.75,
  medium: 0.5,
  low: 0.25,
  none: 0.0
};

// Calculate weighted risk score
let scoreBreakdown = {};
let totalWeightedScore = 0;
let redFlags = [];
let recommendations = [];

riskData.forEach(risk => {
  const weight = riskWeights[risk.clause_type] || 0.01;
  const score = riskScores[risk.risk_level] || 0;
  const weightedScore = score * weight;

  scoreBreakdown[risk.clause_type + '_risk'] = score;
  totalWeightedScore += weightedScore;

  if (risk.risk_level === 'critical' || risk.risk_level === 'high') {
    redFlags.push(risk.risk_description);
    recommendations.push(risk.recommendation);
  }
});

// Check for missing critical clauses
const criticalClauses = ['payment_terms', 'liability', 'termination'];
const foundClauses = clauseData.map(c => c.clause_type);
criticalClauses.forEach(critical => {
  if (!foundClauses.includes(critical)) {
    redFlags.push(`Missing critical clause: ${critical}`);
    recommendations.push(`Add ${critical} clause to contract`);
  }
});

// Check AI confidence levels
const lowConfidenceItems = [...clauseData, ...riskData].filter(item => item.ai_confidence < 0.6);
if (lowConfidenceItems.length > 0) {
  redFlags.push(`${lowConfidenceItems.length} items flagged for manual legal review (low AI confidence)`);
  recommendations.push('Schedule legal review for low-confidence extractions');
}

return {
  clauses: clauseData,
  risks: riskData,
  obligations: obligationData,
  summary: summaryData,
  overall_risk_score: Math.round(totalWeightedScore * 100) / 100,
  score_breakdown: scoreBreakdown,
  red_flags: redFlags,
  recommendations: recommendations,
  calculated_at: new Date().toISOString()
};

